head.script:
scwin.UserID = "";
scwin.UserName = "";
scwin.vCurDate = "";
scwin.BANK_IU_FLAG = false;
scwin.BRANCH_IU_FLAG = false;

scwin.onpageload = async function() {
    scwin.UserID = $c.ses.getUserId();
    scwin.UserName = $c.ses.getUserNm();
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.setCombo();
};

scwin.setCombo = async function() {
    ds_BranchOfcNm.removeAll();
    await $c.sbm.execute(sbm_RetriveBranchofcNm);

    ds_prefDistrict.removeAll();
    await $c.sbm.execute(sbm_RetrivePrefDistrict);

    ds_prefDistrict2.removeAll();
    await $c.sbm.execute(sbm_RetrivePrefDistrict2);
};

scwin.btn_retrieve_onclick = async function(e) {
    scwin.RetriveBranch();
};

scwin.RetriveBranch = async function() {
    let stypeVal = STYPE.getValue();
    if (stypeVal == "0") {
        dma_Search.set("stype", stypeVal);
        dma_Search.set("stext", "");
        ds_Branch.removeAll();
        await $c.sbm.execute(sbm_RetriveBranch);
    } else {
        if ($c.str.trim(STEXT.getValue()) != "") {
            dma_Search.set("stype", stypeVal);
            dma_Search.set("stext", STEXT.getValue());
        } else {
            await $c.win.alert("조회조건이 입력되지 않았습니다.");
            return;
        }
        ds_Branch.removeAll();
        await $c.sbm.execute(sbm_RetriveBranch);
    }
};

scwin.sbm_RetriveBranch_submitdone = async function(e) {
    if (ds_Branch.getRowCount() == 0) {
        await $c.win.alert("조회 결과가 없습니다.");
    }
};

scwin.sbm_RetriveBranch_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_RetriveBranchofcNm_submitdone = async function(e) {
};

scwin.sbm_RetriveBranchofcNm_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_RetrivePrefDistrict_submitdone = async function(e) {
};

scwin.sbm_RetrivePrefDistrict_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_RetrivePrefDistrict2_submitdone = async function(e) {
};

scwin.sbm_RetrivePrefDistrict2_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_RetriveBankInfo_submitdone = async function(e) {
};

scwin.sbm_RetriveBankInfo_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.Input_Check = async function(Flag) {
    switch (Flag) {
        case "RegisterAccount":
            if (ds_Branch.getRowPosition() < 0) {
                await $c.win.alert("지사/사업소 정보를 추가 후 계좌정보를 등록해주세요");
                return false;
            }
            if ($c.str.trim(bankAcntNo.getValue()) == "") {
                await $c.win.alert("계좌번호를 입력하세요");
                bankAcntNo.setFocus();
                return false;
            }
            return true;

        case "SaveBranch":
            if ($c.str.trim(ofcNm.getValue()) == "") {
                await $c.win.alert("상호를 입력하세요");
                ofcNm.setFocus();
                return false;
            }
            if ($c.str.trim(crnNo.getValue()) == "") {
                await $c.win.alert("사업자 번호를 입력하세요");
                crnNo.setFocus();
                return false;
            }
            if ($c.str.trim(picNm.getValue()) == "") {
                await $c.win.alert("대표자명을 입력하세요");
                picNm.setFocus();
                return false;
            }
            if (prefDistrict1.getValue() == "" || prefDistrict2.getValue() == "") {
                await $c.win.alert("선호권역은 임의로 입력할 수 없습니다.");
                return false;
            }
            if (!$c.gus.fn_isBusiNoByValue($c.str.trim(crnNo.getValue()))) {
                await $c.win.alert("잘못된 사업자 번호입니다.");
                crnNo.setFocus();
                return false;
            }
            return true;

        default:
            break;
    }
    return true;
};

scwin.RegisterAccount = async function() {
    if (!(await scwin.Input_Check("RegisterAccount"))) return;

    dma_SaveBankInfo.set("bankCd", prefDistrict2.getValue());
    dma_SaveBankInfo.set("bankAcntNo", bankAcntNo.getValue());
    dma_SaveBankInfo.set("dpstr", dpstr.getValue());
    dma_SaveBankInfo.set("rmk", accountRmk.getValue());
    dma_SaveBankInfo.set("ez106Idx", ds_Branch.getCellData(ds_Branch.getRowPosition(), "ez106Idx"));

    if (scwin.BANK_IU_FLAG) {
        dma_SaveBankInfo.set("ez114Idx", "0");
    } else {
        dma_SaveBankInfo.set("ez114Idx", ds_BankList.getCellData(ds_BankList.getRowPosition(), "ez114Idx"));
    }

    await $c.sbm.execute(sbm_SaveBankInfo);
};

scwin.sbm_SaveBankInfo_submitdone = async function(e) {
    if (ds_result.getCellData(0, "outMsg") == "1.0") {
        if (scwin.BANK_IU_FLAG) {
            await $c.win.alert("계좌 등록 완료");
            scwin.BANK_IU_FLAG = false;
        } else {
            await $c.win.alert("계좌 수정 완료");
        }
    } else {
        await $c.win.alert("계좌 등록 실패");
    }
    scwin.RetrieveAccount();
};

scwin.sbm_SaveBankInfo_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.DeleteBankInfo = async function() {
    if (ds_BankList.getRowPosition() < 0) return;
    let chk = await $c.win.confirm("선택하신 계좌정보를 삭제 하시겠습니까?");
    if (!chk) return;

    dma_DeleteBankInfo.set("userId", scwin.UserID);
    dma_DeleteBankInfo.set("ez114Idx", ds_BankList.getCellData(ds_BankList.getRowPosition(), "ez114Idx"));

    await $c.sbm.execute(sbm_DeleteBankInfo);
};

scwin.sbm_DeleteBankInfo_submitdone = async function(e) {
    if (ds_result.getCellData(0, "outMsg") == "1.0") {
        await $c.win.alert("삭제완료");
    } else {
        await $c.win.alert("삭제실패");
    }

    bankAcntNo.setValue("");
    dpstr.setValue("");
    accountRmk.setValue("");
    scwin.RetrieveAccount();
};

scwin.sbm_DeleteBankInfo_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.addAccount = async function() {
    scwin.BANK_IU_FLAG = true;
    bankAcntNo.setValue("");
    dpstr.setValue("");
    accountRmk.setValue("");
    prefDistrict2.setSelectedIndex(0);
};

scwin.RetrieveAccount = async function() {
    if (ds_Branch.getRowPosition() < 0) return;

    ds_BankList.removeAll();
    dma_Search.set("stype", "");
    dma_Search.set("stext", "");
    // TODO: ez106Idx 파라미터 전달 방식 확인 필요
    await $c.sbm.execute(sbm_RetriveBankInfo);
};

scwin.f_ClearData = async function() {
    ofcNm.setValue("");
    telNo.setValue("");
    faxNo.setValue("");
    crnNo.setValue("");
    picNm.setValue("");
    handphoneNo.setValue("");
    picSsn.setValue("");
    bizcond.setValue("");
    catBusi.setValue("");
    rmk.setValue("");
    coDtlAddr_textbox.setValue("");
    coZipcode.setValue("");
    dtlAddr_textbox.setValue("");
    zipcode.setValue("");
    chk_taxinvcYn.setValue("");

    prefDistrict1.setValue("");
    prefDistrict2.setValue("");
    bankAcntNo.setValue("");
    dpstr.setValue("");
    accountRmk.setValue("");
    scwin.BRANCH_IU_FLAG = false;

    combo_branch.setDisabled(false);

    let bhofficeVal = "";
    let comboIdx = combo_branch.getSelectedIndex();
    if (comboIdx >= 0) {
        bhofficeVal = ds_BranchOfcNm.getCellData(comboIdx, "bhofficeIdx");
    }

    if (bhofficeVal == "0") {
        ra_branch.setValue("1");
    } else {
        ra_branch.setValue("2");
    }
};

scwin.btn_clear_onclick = async function(e) {
    scwin.f_ClearData();
};

scwin.f_DeleteBranch = async function() {
    let rowPos = ds_Branch.getRowPosition();
    if (rowPos < 0) return;

    let chk = await $c.win.confirm("선택하신  [" + ds_Branch.getCellData(rowPos, "ofcNm") + "] 을/를 삭제 하시겠습니까?");
    if (!chk) return;

    dma_DeleteBranch.set("hdofficeIdx", ds_Branch.getCellData(rowPos, "hdofficeIdx"));
    dma_DeleteBranch.set("bhofficeIdx", ds_Branch.getCellData(rowPos, "bhofficeIdx"));
    dma_DeleteBranch.set("officeIdx", ds_Branch.getCellData(rowPos, "officeIdx"));
    dma_DeleteBranch.set("ez106Idx", ds_Branch.getCellData(rowPos, "ez106Idx"));
    dma_DeleteBranch.set("regId", scwin.UserID);

    await $c.sbm.execute(sbm_DeleteBranch);
};

scwin.btn_delete_onclick = async function(e) {
    scwin.f_DeleteBranch();
};

scwin.sbm_DeleteBranch_submitdone = async function(e) {
    if (ds_result.getRowCount() > 0 && ds_result.getCellData(0, "outMsg") != null && ds_result.getCellData(0, "outMsg") != "") {
        await $c.win.alert(ds_result.getCellData(0, "outMsg"));
    }
    scwin.f_ClearData();
    scwin.RetriveBranch();
};

scwin.sbm_DeleteBranch_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_SaveBranch = async function() {
    if (!(await scwin.Input_Check("SaveBranch"))) return;

    let rowPos = ds_Branch.getRowPosition();

    if (scwin.BRANCH_IU_FLAG) {
        dma_SaveBranch.set("iuFlag", "U");
        dma_SaveBranch.set("ihdofficeIdx", ds_Branch.getCellData(rowPos, "hdofficeIdx"));
        dma_SaveBranch.set("ibhofficeIdx", ds_Branch.getCellData(rowPos, "bhofficeIdx"));
        dma_SaveBranch.set("iofficeIdx", ds_Branch.getCellData(rowPos, "officeIdx"));
    } else {
        dma_SaveBranch.set("iuFlag", "I");
        let comboIdx = combo_branch.getSelectedIndex();
        if (comboIdx >= 0) {
            dma_SaveBranch.set("ihdofficeIdx", ds_BranchOfcNm.getCellData(comboIdx, "hdofficeIdx"));
            dma_SaveBranch.set("ibhofficeIdx", ds_BranchOfcNm.getCellData(comboIdx, "bhofficeIdx"));
            dma_SaveBranch.set("iofficeIdx", ds_BranchOfcNm.getCellData(comboIdx, "officeIdx"));
        }
    }

    let raBranchVal = ra_branch.getValue();
    if (raBranchVal == "0") {
        dma_SaveBranch.set("officeTyp", "0");
    } else if (raBranchVal == "1") {
        dma_SaveBranch.set("officeTyp", "1");
    } else {
        dma_SaveBranch.set("officeTyp", "2");
    }

    if (rowPos >= 0) {
        dma_SaveBranch.set("ez108Idx", ds_Branch.getCellData(rowPos, "ez108Idx"));
        dma_SaveBranch.set("ez106Idx", ds_Branch.getCellData(rowPos, "ez106Idx"));
    } else {
        dma_SaveBranch.set("ez108Idx", "");
        dma_SaveBranch.set("ez106Idx", "");
    }

    dma_SaveBranch.set("ofcNm", ofcNm.getValue());
    dma_SaveBranch.set("bizcond", bizcond.getValue());
    dma_SaveBranch.set("catBusi", catBusi.getValue());

    dma_SaveBranch.set("prefDistrict1", prefDistrict1.getText());
    dma_SaveBranch.set("prefDistrict1Cd", prefDistrict1.getValue());
    dma_SaveBranch.set("prefDistrict2", prefDistrict2.getText());
    dma_SaveBranch.set("prefDistrict2Cd", prefDistrict2.getValue());

    dma_SaveBranch.set("telNo", telNo.getValue().replace(/-/g, ""));
    dma_SaveBranch.set("faxNo", faxNo.getValue().replace(/-/g, ""));
    dma_SaveBranch.set("zipcode", coZipcode.getValue());
    dma_SaveBranch.set("dtlAddr", coDtlAddr_textbox.getValue());

    let taxinvcYnVal = chk_taxinvcYn.getValue();
    if (taxinvcYnVal != null && taxinvcYnVal != "") {
        dma_SaveBranch.set("taxinvcYn", "Y");
    } else {
        dma_SaveBranch.set("taxinvcYn", "N");
    }

    dma_SaveBranch.set("dmZipcode", zipcode.getValue());
    dma_SaveBranch.set("regId", scwin.UserID);
    dma_SaveBranch.set("dmDtlAddr", dtlAddr_textbox.getValue());
    dma_SaveBranch.set("rmk", rmk.getValue());
    dma_SaveBranch.set("picNm", picNm.getValue());
    dma_SaveBranch.set("handphoneNo", handphoneNo.getValue().replace(/-/g, ""));
    dma_SaveBranch.set("picSsn", picSsn.getValue());
    dma_SaveBranch.set("crnNo", crnNo.getValue());

    await $c.sbm.execute(sbm_SavaBranch);
};

scwin.btn_save_onclick = async function(e) {
    scwin.f_SaveBranch();
};

scwin.sbm_SavaBranch_submitdone = async function(e) {
    if (ds_result.getRowCount() > 0 && ds_result.getCellData(0, "outMsg") != null && ds_result.getCellData(0, "outMsg") != "") {
        await $c.win.alert(ds_result.getCellData(0, "outMsg"));
    }
    scwin.RetriveBranch();
};

scwin.sbm_SavaBranch_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.ShowUser = async function() {
    let sUrl = "/ui/bp/fbp/bi/ez_104_01_01p.xml";
    await $c.win.openPopup(sUrl, {
        width: 620,
        height: 380,
        modal: false,
        title: "화물복사"
    });
};

scwin.navi025_onclick = function(e) {
    scwin.ShowUser();
};

scwin.gr_bankacc_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex < 0) return;
    scwin.BANK_IU_FLAG = false;

    let bankNm = ds_BankList.getCellData(rowIndex, "accountNm");
    // TODO: bankCdVal_combo에 해당하는 은행명 콤보 매핑 확인 필요
    prefDistrict2.setValue(bankNm);
    bankAcntNo.setValue(ds_BankList.getCellData(rowIndex, "bankAcntNo"));
    dpstr.setValue(ds_BankList.getCellData(rowIndex, "dpstr"));
    accountRmk.setValue(ds_BankList.getCellData(rowIndex, "rmk"));
};

scwin.gr_office_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex < 0) return;

    let officeTypVal = ds_Branch.getCellData(rowIndex, "officeTyp");
    if (officeTypVal == "본사") {
        ra_branch.setValue("0");
    } else if (officeTypVal == "지사") {
        ra_branch.setValue("1");
    } else {
        ra_branch.setValue("2");
    }

    let taxinvcYnVal = ds_Branch.getCellData(rowIndex, "taxinvcYn");
    if (taxinvcYnVal == "가능") {
        chk_taxinvcYn.setValue("Y");
    } else {
        chk_taxinvcYn.setValue("");
    }

    let branchVal = ds_Branch.getCellData(rowIndex, "branch");
    combo_branch.setValue(branchVal);
    combo_branch.setDisabled(true);

    ofcNm.setValue(ds_Branch.getCellData(rowIndex, "ofcNm"));
    telNo.setValue(ds_Branch.getCellData(rowIndex, "telNo"));
    faxNo.setValue(ds_Branch.getCellData(rowIndex, "faxNo"));
    prefDistrict1.setValue(ds_Branch.getCellData(rowIndex, "prefDistrict1"));
    prefDistrict2.setValue(ds_Branch.getCellData(rowIndex, "prefDistrict2"));
    crnNo.setValue(ds_Branch.getCellData(rowIndex, "crnNo"));
    picNm.setValue(ds_Branch.getCellData(rowIndex, "picNm"));
    handphoneNo.setValue(ds_Branch.getCellData(rowIndex, "handphoneNo"));
    picSsn.setValue(ds_Branch.getCellData(rowIndex, "picSsn"));
    bizcond.setValue(ds_Branch.getCellData(rowIndex, "bizcond"));
    catBusi.setValue(ds_Branch.getCellData(rowIndex, "catBusi"));
    rmk.setValue(ds_Branch.getCellData(rowIndex, "rmk"));
    coDtlAddr_textbox.setValue(ds_Branch.getCellData(rowIndex, "dtlAddr"));
    coZipcode.setValue(ds_Branch.getCellData(rowIndex, "zipcode"));
    dtlAddr_textbox.setValue(ds_Branch.getCellData(rowIndex, "dmDtlAddr"));
    zipcode.setValue(ds_Branch.getCellData(rowIndex, "dmZipcode"));

    bankAcntNo.setValue("");
    dpstr.setValue("");
    accountRmk.setValue("");
    prefDistrict2.setSelectedIndex(0);

    scwin.BRANCH_IU_FLAG = true;
    scwin.RetrieveAccount();
};

scwin.gr_office_oncelldblclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex < 0) return;
};

scwin.combo_branch_onchange = function(e) {
    let comboIdx = combo_branch.getSelectedIndex();
    if (comboIdx >= 0) {
        let bhofficeVal = ds_BranchOfcNm.getCellData(comboIdx, "bhofficeIdx");
        if (bhofficeVal == "0") {
            ra_branch.setValue("1");
        } else {
            ra_branch.setValue("2");
        }
    }
};

scwin.btn_trigger3_onclick = function(e) {
    scwin.addAccount();
};

scwin.btn_trigger4_onclick = function(e) {
    scwin.RegisterAccount();
};

scwin.btn_del_onclick = function(e) {
    scwin.DeleteBankInfo();
};

scwin.f_RunExcel = function() {
    $c.data.downloadGridViewExcel(gr_bankacc, {
        fileName: "지사 사업소 목록.xlsx",
        sheetName: "지사 사업소 목록"
    });
};
